import base64,zlib,traceback
try:
    exec(compile(zlib.decompress(base64.b64decode('')).decode('utf-8'),'streamlit_app.py','exec'))
except Exception:
    import streamlit as st
    st.set_page_config(page_title='Sim Market Lab - Error', layout='wide')
    st.error('La app encontró un error. Copiá el traceback para corregirlo.')
    st.code(traceback.format_exc(), language='python')
